library(haven); library(dplyr); library(readr); dir.create("data/output", showWarnings=FALSE, recursive=TRUE); w1 <- read_delim("data/input/wave_one_lsype_young_person_2020.tab", delim="\t", show_col_types=FALSE); w2 <- read_delim("data/input/wave_two_lsype_family_background_2020.tab", delim="\t", show_col_types=FALSE); w3 <- read_delim("data/input/wave_three_lsype_family_background_2020.tab", delim="\t", show_col_types=FALSE); w4 <- read_delim("data/input/wave_four_lsype_young_person_2020.tab", delim="\t", show_col_types=FALSE); w8 <- read_delim("data/input/ns8_2015_derived.tab", delim="\t", show_col_types=FALSE); w9d <- read_delim("data/input/ns9_2022_derived_variables.tab", delim="\t", show_col_types=FALSE); w9m <- read_delim("data/input/ns9_2022_main_interview.tab", delim="\t", show_col_types=FALSE); w2 <- rename(w2, regub15=urbind, regov15=gor); w3 <- rename(w3, regub16=urbind, regov16=gor); w8 <- rename(w8, regov25=W8DGOR); w9d <- rename(w9d, regov32=W9DRGN); w9m <- rename(w9m, regnat32=W9NATIONRES); d <- full_join(w1, w2, by="NSID"); d <- full_join(d, w3, by="NSID"); d <- full_join(d, w4, by="NSID"); d <- full_join(d, w8, by="NSID"); d <- full_join(d, w9d, by="NSID"); d <- full_join(d, w9m, by="NSID"); d <- mutate(d, regub15=ifelse(regub15==-94, -8, regub15), regub15=ifelse(is.na(regub15), -3, regub15), regov15=ifelse(regov15==-94, -8, regov15), regov15=ifelse(is.na(regov15), -3, regov15), regub16=ifelse(regub16==-94, -8, regub16), regub16=ifelse(is.na(regub16), -3, regub16), regov16=ifelse(regov16==-94, -8, regov16), regov16=ifelse(is.na(regov16), -3, regov16)); d <- mutate(d, ukres32=case_when(regnat32 %in% c(1,2,3,4) ~ 1, regnat32==5 ~ 2, regnat32 %in% c(-9,-8,-3,-1) ~ regnat32, TRUE ~ -3)); d <- mutate(d, regov_harmonised=case_when(!is.na(regov32) & regov32>0 ~ regov32, !is.na(regov25) & regov25>0 ~ regov25, !is.na(regov16) & regov16>0 ~ regov16, !is.na(regov15) & regov15>0 ~ regov15, TRUE ~ -3)); out <- select(d, NSID, regub15, regub16, regov15, regov16, regov25, regov32, regnat32, ukres32, regov_harmonised); write_csv(out, "data/output/cleaned_data.csv"); cat("Done:", nrow(out), "rows,", ncol(out), "cols\n")